// 例子，遍历所有页面子节点
async function traverseAndLogDom(node) {
  if (!node) return;
  // 遍历子节点
  let child = node.firstChild;
  while (child) {
    // 后续代码放到异步队列
    await new Promise((resolve) => setTimeout(resolve, 0));
    traverseAndLogDom(child);
    child = child.nextSibling;
  }
}

traverseAndLogDom(document.documentElement);

